@function pow($base, $exponent, $prec: 16) {
  @if (floor($exponent) != $exponent) {
    $prec2: pow(10, $prec);
    $exponent: round($exponent * $prec2);
    $denominator: gcd($exponent, $prec2);
    @return nth-root(pow($base, divide($exponent, $denominator)), divide($prec2, $denominator), $prec);
  }

  $value: $base;
  @if $exponent > 1 {
    @for $i from 2 through $exponent {
      $value: $value * $base;
    }
  }
  @else if $exponent < 1 {
    @for $i from 0 through -$exponent {
      $value: divide($value, $base);
    }
  }

  @return $value;
}

@function rem-calc($values, $base: null) {
  $rem-values: ();
  $count: length($values);

  // If no base is defined, defer to the global font size
  @if $base == null {
    $base: $global-font-size;
  }

  // If the base font size is a %, then multiply it by 16px
  // This is because 100% font size = 16px in most all browsers
  @if unit($base) == '%' {
    $base: divide($base, 100%) * 16px;
  }

  // Using rem as base allows correct scaling
  @if unit($base) == 'rem' {
    $base: strip-unit($base) * 16px;
  }

  @if $count == 1 {
    @return -zf-to-rem($values, $base);
  }

  @for $i from 1 through $count {
    $rem-values: append($rem-values, -zf-to-rem(nth($values, $i), $base));
  }

  @return $rem-values;
}

@function -zf-to-rem($value, $base: null) {
  // Check if the value is a number
  @if type-of($value) != 'number' {
    @if $unit-warnings {
      @warn inspect($value) + ' was passed to rem-calc(), which is not a number.';
    }
    @return $value;
  }

  // Transform em into rem if someone hands over 'em's
  @if unit($value) == 'em' {
    $value: strip-unit($value) * 1rem;
  }

  // Calculate rem if units for $value is not rem or em
  @if unit($value) != 'rem' {
    $value: divide(strip-unit($value), strip-unit($base)) * 1rem;
  }

  // Turn 0rem into 0
  @if $value == 0rem {
    $value: 0;
  }

  @return $value;
}

// Media that spans multiple breakpoint widths.
// Makes the @content apply between the min and max breakpoints
@mixin media-breakpoint-between($lower, $upper, $breakpoints: $grid-breakpoints) {
  $min: breakpoint-min($lower, $breakpoints);
  $max: breakpoint-max($upper, $breakpoints);

  @if $min != null and $max != null {
    @media (min-width: $min) and (max-width: $max) {
      @content;
    }
  } @else if $max == null {
    @include media-breakpoint-up($lower, $breakpoints) {
      @content;
    }
  } @else if $min == null {
    @include media-breakpoint-down($upper, $breakpoints) {
      @content;
    }
  }
}

// Media between the breakpoint's minimum and maximum widths.
// No minimum for the smallest breakpoint, and no maximum for the largest one.
// Makes the @content apply only to the given breakpoint, not viewports any wider or narrower.
@mixin media-breakpoint-only($name, $breakpoints: $grid-breakpoints) {
  $min:  breakpoint-min($name, $breakpoints);
  $next: breakpoint-next($name, $breakpoints);
  $max:  breakpoint-max($next, $breakpoints);

  @if $min != null and $max != null {
    @media (min-width: $min) and (max-width: $max) {
      @content;
    }
  } @else if $max == null {
    @include media-breakpoint-up($name, $breakpoints) {
      @content;
    }
  } @else if $min == null {
    @include media-breakpoint-down($next, $breakpoints) {
      @content;
    }
  }
}

@mixin breakpoint-up($name, $breakpoints: $grid-breakpoints) {
  @if meta.type-of($name) == 'number' {
    @media (min-width: $name) {
      @content;
    }
  } @else if map.has-key($breakpoints, $name) {
    $breakpoint: map.get($breakpoints, $name);
    $width: map.get($breakpoint, width);
    @if is-smallest-breakpoint($name, $breakpoints) {
      @content;
    } @else {
      @media (min-width: $width) {
        @content;
      }
    }
  } @else {
    @error 'Unable to find a breakpoint with name `#{$name}`. Expected one of: (#{map.keys($breakpoints)})';
  }
}

@function fraction-to-percentage(
  $fraction,
  $denominator: null
) {
  $parsed: zf-parse-fraction($fraction);
  $parsed-nominator: nth($parsed, 1);
  $parsed-denominator: nth($parsed, 2);

  @if $parsed-nominator == null {
    @error 'Wrong syntax for "fraction-to-percentage()". Use a number, decimal, percentage, or "n of n" / "n/n".';
  }
  @if $parsed-denominator == null {
    @if type-of($denominator) == 'number' {
      $parsed-denominator: $denominator;
    }
    @else {
      @error 'Error with "fraction-to-percentage()". A default "$denominator" is required to support absolute values';
    }
  }

  @return percentage(divide($parsed-nominator, $parsed-denominator));
}

@function color-pick-contrast($base, $colors: ($white, $black), $tolerance: $global-color-pick-contrast-tolerance) {
  $contrast: color-contrast($base, nth($colors, 1));
  $best: nth($colors, 1);

  @for $i from 2 through length($colors) {
    $current-contrast: color-contrast($base, nth($colors, $i));
    @if ($current-contrast - $contrast > $tolerance) {
      $contrast: color-contrast($base, nth($colors, $i));
      $best: nth($colors, $i);
    }
  }

  @if ($contrast-warnings and $contrast < 3) {
    @warn 'Contrast ratio of #{$best} on #{$base} is pretty bad, just #{$contrast}';
  }

  @return $best;
}

@mixin button-variant($color: $primary-color) {
  background: $color;
  border-color: darken($color, 3%);
  color: $light-color;
  &:focus {
    @include control-shadow($color);
  }
  &:focus,
  &:hover {
    background: darken($color, 2%);
    border-color: darken($color, 5%);
    color: $light-color;
  }
  &:active,
  &.active {
    background: darken($color, 7%);
    border-color: darken($color, 10%);
    color: $light-color;
  }
  &.loading {
    &::after {
      border-bottom-color: $light-color;
      border-left-color: $light-color;
    }
  }
}

@function color-contrast($background, $color-contrast-dark: $color-contrast-dark, $color-contrast-light: $color-contrast-light, $min-contrast-ratio: $min-contrast-ratio) {
  $foregrounds: $color-contrast-light, $color-contrast-dark, $white, $black;
  $max-ratio: 0;
  $max-ratio-color: null;

  @each $color in $foregrounds {
    $contrast-ratio: contrast-ratio($background, $color);
    @if $contrast-ratio >= $min-contrast-ratio {
      @return $color;
    } @else if $contrast-ratio > $max-ratio {
      $max-ratio: $contrast-ratio;
      $max-ratio-color: $color;
    }
  }

  @warn "Found no color leading to #{$min-contrast-ratio}:1 contrast ratio against #{$background}...";

  @return $max-ratio-color;
}

@mixin -percent-column-span($breakpoints, $percent) {
  @each $key, $value in $breakpoints {
    $columns: get-column-count($breakpoints, $key);
    $span: $columns * $percent;

    @if is-smallest-breakpoint($key, $breakpoints) {
      --cds-grid-columns: #{$span};

      grid-column: span list.slash($span, span) #{$span};
    } @else {
      $previous-breakpoint: breakpoint-prev($key, $breakpoints);
      $previous-column-count: get-column-count(
        $breakpoints,
        $previous-breakpoint
      );
      $previous-span: $previous-column-count * $percent;

      @if $span != $previous-span {
        @include breakpoint($key) {
          --cds-grid-columns: #{$span};

          grid-column: span list.slash($span, span) #{$span};
        }
      }
    }
  }
}

@each $key, $value in $breakpoints {
  $columns: get-column-count($breakpoints, $key);
  $span: $columns * $percent;

  @if is-smallest-breakpoint($key, $breakpoints) {
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  } @else {
    $previous-breakpoint: breakpoint-prev($key, $breakpoints);
    $previous-column-count: get-column-count(
      $breakpoints,
      $previous-breakpoint
    );
    $previous-span: $previous-column-count * $percent;

    @if $span != $previous-span {
      @include breakpoint($key) {
        --cds-grid-columns: #{$span};

        grid-column: span list.slash($span, span) #{$span};
      }
    }
  }
}

@mixin -make-container($breakpoints: $grid-breakpoints) {
  margin-inline: auto;

  @include -set-largest-breakpoint($breakpoints);

  @each $name, $value in $breakpoints {
    $prev-breakpoint: map.get($breakpoints, breakpoint-prev($name));
    $margin: map.get($value, margin);

    @if $prev-breakpoint {
      $prev-margin: map.get($prev-breakpoint, margin);
      @if $prev-margin != $margin {
        @include breakpoint($name) {
          padding-inline: #{($grid-gutter * 0.5) + $margin};
        }
      }
    } @else {
      @include breakpoint($name) {
        padding-inline: #{($grid-gutter * 0.5) + $margin};
      }
    }
  }
}

@else {
  // One child
  &:first-child {
    &:last-child {
      width: calc(100% - #{$spacing});
    }
  }

  // Two or more childreen
  @for $i from 2 through $buttongroup-expand-max {
    &:first-child:nth-last-child(#{$i}) {
      &, &:first-child:nth-last-child(#{$i}) ~ #{$selector} {
        display: inline-block;
        width: calc(#{percentage(divide(1, $i))} - #{$spacing});
        margin-#{$global-right}: $spacing;

        &:last-child {
          margin-#{$global-right}: $spacing * -$buttongroup-expand-max;
        }
      }
    }
  }
}

@function xy-cell-offset(
  $n,
  $gutters: $grid-margin-gutters,
  $gutter-type: margin,
  $breakpoint: null
) {
  $breakpoint: -zf-current-breakpoint($breakpoint, $default: $-zf-zero-breakpoint);
  $size: xy-cell-size($n);

  $offset: $size;
  @if ($gutter-type == 'margin') {
    // Make sure that 0 is translated in 0rem for calc()
    $gutter: rem-calc(xy-cell-gutters($gutters, $breakpoint));
    @if $gutter == 0 {
      // sass-lint:disable zero-unit
      $gutter: 0rem;
    }
    $offset: if($gutter == 0, $size, calc(#{$size} + #{$gutter} / 2));
  }
  @return $offset;
}

@include -zf-each-breakpoint() {
  // Responsive "auto" modifier
  @if not($-zf-size == $-zf-zero-breakpoint) {
    > .#{$-zf-size}-auto {
      @include xy-cell(auto, $gutter-type: none, $vertical: true);
    }
  }

  %-xy-cell-base-shrink-vertical-#{$-zf-size} {
    @include xy-cell-base(shrink);
  }

  // Responsive "shrink" modifier
  @if not($-zf-size == $-zf-zero-breakpoint) {
    > .#{$-zf-size}-shrink {
      @extend %-xy-cell-base-shrink-vertical-#{$-zf-size};
      @include xy-cell-size(shrink, $gutter-type: none, $vertical: true);
    }
  }

  // Responsive width modifiers
  @for $i from 1 through $grid-columns {
    // Sizing (percentage)
    > .#{$-zf-size}-#{$i} {
      @extend %-xy-cell-base-shrink-vertical-#{$-zf-size};
      @include xy-cell-size($i, $gutter-type: none, $vertical: true);
    }
  }

}

@each $_inuit-spacing-unit in
      $inuit-global-spacing-unit-factor-tiny
      $inuit-global-spacing-unit-factor-small
      $inuit-global-spacing-unit-factor-large
      $inuit-global-spacing-unit-factor-huge {

  @if (type-of($_inuit-spacing-unit) == number) {

    @if (unitless($_inuit-spacing-unit) == false) {
      @error "`#{$_inuit-spacing-unit}` needs to be unitless.";
    }

    @if ($_inuit-spacing-unit != ceil($_inuit-spacing-unit)) {
      @error "`#{$_inuit-spacing-unit}` needs to be an integer.";
    }

  } @else {
    @error "`#{$_inuit-spacing-unit}` needs to be a number.";
  }

}

@mixin css-triangle(
  $triangle-size,
  $triangle-color,
  $triangle-direction
) {
  display: block;
  width: 0;
  height: 0;

  border-style: solid;
  border-width: $triangle-size;

  content: '';

  @if ($triangle-direction == down) {
    border-bottom-width: 0;
    border-color: $triangle-color transparent transparent;
  }
  @if ($triangle-direction == up) {
    border-top-width: 0;
    border-color: transparent transparent $triangle-color;
  }
  @if ($triangle-direction == right) {
    border-right-width: 0;
    border-color: transparent transparent transparent $triangle-color;
  }
  @if ($triangle-direction == left) {
    border-left-width: 0;
    border-color: transparent $triangle-color transparent transparent;
  }
}

@function bulmaColorBrightness($n) {
  $color-brightness: math.round(
    math.div(
      (color.channel($n, "red", $space: rgb) * 299) +
        (color.channel($n, "green", $space: rgb) * 587) +
        (color.channel($n, "blue", $space: rgb) * 114),
      1000
    )
  );
  $light-color: math.round(
    math.div(
      (color.channel(#ffffff, "red", $space: rgb) * 299) +
        (color.channel(#ffffff, "green", $space: rgb) * 587) +
        (color.channel(#ffffff, "blue", $space: rgb) * 114),
      1000
    )
  );

  @if abs($color-brightness) < math.div($light-color, 2) {
    @return "dark";
  }

  @return "bright";
}

@mixin hide-visually($toggle: "hide") {
  @if not index("hide" "unhide", $toggle) {
    @error "`#{$toggle}` is not a valid value for the `$toggle` argument in " +
      "the `hide-visually` mixin. Must be either `hide` or `unhide`.";
  } @else if $toggle == "hide" {
    border: 0;
    clip: rect(1px, 1px, 1px, 1px);
    clip-path: inset(100%);
    height: 1px;
    overflow: hidden;
    padding: 0;
    position: absolute;
    white-space: nowrap;
    width: 1px;
  } @else if $toggle == "unhide" {
    clip: auto;
    clip-path: none;
    height: auto;
    overflow: visible;
    position: static;
    white-space: inherit;
    width: auto;
  }
}

@mixin -make-col-ready(
  $gutter: $grid-gutter,
  $condensed-gutter: $grid-gutter-condensed
) {
  // Prevent columns from becoming too narrow when at smaller grid tiers by
  // always setting `width: 100%;`. This works because we use `flex` values
  // later on to override this initial width.
  inline-size: 100%;
  padding-inline: $gutter * 0.5;

  // For our condensed use-case, our gutters collapse to 2px solid, 1px on each
  // side.
  .#{$prefix}--row--condensed &,
  .#{$prefix}--grid--condensed & {
    padding-inline: $condensed-gutter * 0.5;
  }

  // For our narrow use-case, our container hangs 16px into the gutter
  .#{$prefix}--row--narrow &,
  .#{$prefix}--grid--narrow & {
    padding-inline: 0 $gutter * 0.5;
  }
}

@mixin -make-col-ready(
  $gutter: $grid-gutter,
  $condensed-gutter: $grid-gutter--condensed
) {
  // Prevent columns from becoming too narrow when at smaller grid tiers by
  // always setting `width: 100%;`. This works because we use `flex` values
  // later on to override this initial width.
  inline-size: 100%;
  padding-inline: ($gutter * 0.5);

  // For our condensed use-case, our gutters collapse to 2px solid, 1px on each
  // side.
  .#{$prefix}--row--condensed &,
  .#{$prefix}--grid--condensed & {
    padding-inline: ($condensed-gutter * 0.5);
  }

  // For our narrow use-case, our container hangs 16px into the gutter
  .#{$prefix}--row--narrow &,
  .#{$prefix}--grid--narrow & {
    padding-inline: 0 ($gutter * 0.5);
  }
}

@mixin button-base {
  display: inline-block;
  vertical-align: middle;
  margin: $button-margin;
  border: $button-border;
  border-radius: $button-radius;
  transition: $button-transition;
  font-family: $button-font-family;
  font-size: map-get($button-sizes, default);
  font-weight: $button-font-weight;
  -webkit-appearance: none; // sass-lint:disable-line no-vendor-prefixes
  line-height: 1;
  text-align: center;
  cursor: pointer;

  @if (type-of($button-padding) == 'map') {
    @each $size, $padding in $button-padding {
      @include breakpoint($size) {
        padding: $padding;
      }
    }
  }
  @else {
    padding: $button-padding;
  }

  @include disable-mouse-outline;
}

// Box header
.card-header {
  position: relative;
  padding: (($card-spacer-y * .5) * 2) $card-spacer-x;
  background-color: transparent;
  border-bottom: 1px solid $card-border-color;

  @if $enable-rounded {
    @include border-top-radius($border-radius);
  }

  .collapsed-card & {
    border-bottom: 0;
  }

  > .card-tools {
    float: right;
    margin-right: -$card-spacer-x * .5;

    .input-group,
    .nav,
    .pagination {
      margin-top: -$card-spacer-y * .4;
      margin-bottom: -$card-spacer-y * .4;
    }

    [data-bs-toggle="tooltip"] {
      position: relative;
    }
  }
}

// Button Primary
  &.btn-primary {
    background: $primary-color;
    border-color: $primary-color-dark;
    color: $light-color;
    &:focus,
    &:hover {
      background: darken($primary-color-dark, 2%);
      border-color: darken($primary-color-dark, 5%);
      color: $light-color;
    }
    &:active,
    &.active {
      background: darken($primary-color-dark, 4%);
      border-color: darken($primary-color-dark, 7%);
      color: $light-color;
    }
    &.loading {
      &::after {
        border-bottom-color: $light-color;
        border-left-color: $light-color;
      }
    }
  }

@mixin hook-inverse-component-pagination(){

    .uk-pagination > * > * {
        color: $inverse-pagination-item-color;
        @if(meta.mixin-exists(hook-inverse-pagination-item)) {@include hook-inverse-pagination-item();}
    }

    .uk-pagination > * > :hover {
        color: $inverse-pagination-item-hover-color;
        @if(meta.mixin-exists(hook-inverse-pagination-item-hover)) {@include hook-inverse-pagination-item-hover();}
    }

    .uk-pagination > .uk-active > * {
        color: $inverse-pagination-item-active-color;
        @if(meta.mixin-exists(hook-inverse-pagination-item-active)) {@include hook-inverse-pagination-item-active();}
    }

    .uk-pagination > .uk-disabled > * {
        color: $inverse-pagination-item-disabled-color;
        @if(meta.mixin-exists(hook-inverse-pagination-item-disabled)) {@include hook-inverse-pagination-item-disabled();}
    }

}

@mixin emit-layout-tokens-to-shadow-host($host-selector) {
  @each $group, $properties in $layout-tokens {
    @each $property, $steps in $properties {
      @each $step, $value in $steps {
        :host(#{$host-selector}[#{$group}='#{$step}']) {
          @include custom-property.declaration(
            'layout-#{$group}-#{$property}-context',
            custom-property.get-var(
              'layout-#{$group}-#{$property}-#{$step}',
              $value
            )
          );
          @include custom-property.declaration(
            'layout-#{$group}-#{$property}',
            custom-property.get-var('layout-#{$group}-#{$property}-context')
          );
        }
      }
    }
  }
}

@each $group, $properties in $layout-tokens {
  @each $property, $steps in $properties {
    @each $step, $value in $steps {
      :host(#{$host-selector}[#{$group}='#{$step}']) {
        @include custom-property.declaration(
          'layout-#{$group}-#{$property}-context',
          custom-property.get-var(
            'layout-#{$group}-#{$property}-#{$step}',
            $value
          )
        );
        @include custom-property.declaration(
          'layout-#{$group}-#{$property}',
          custom-property.get-var('layout-#{$group}-#{$property}-context')
        );
      }
    }
  }
}

@each $group in $-components {
  @each $key, $value in $group {
    @if meta.type-of($value) == map {
      $fallback: map.get($value, fallback);
      $theme-values: map.get($value, values);

      @each $theme-value in $theme-values {
        $value: map.get($theme-value, value);

        @if theme.matches(map.get($theme-value, theme), $theme) and
          meta.type-of($value) ==
          color
        {
          @include custom-property.declaration($key, $value);
        }
      }
    } @else if meta.type-of($value) == color {
      @include custom-property.declaration($key, $value);
    }
  }
}

@if not(
  enabled('enable-experimental-focus-wrap-without-sentinels') or
    $enable-experimental-focus-wrap-without-sentinels or
    enabled('enable-focus-wrap-without-sentinels') or
    $enable-focus-wrap-without-sentinels or
    enabled('enable-dialog-element') or
    $enable-dialog-element
)
{
  position: fixed;
  z-index: z('modal');
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: $overlay;
  block-size: 100vh;
  content: '';
  inline-size: 100vw;
  inset-block-start: 0;
  inset-inline-start: 0;

  &.#{$prefix}--modal--enable-presence {
    @include modal-animations($has-presence: true);
  }

  &:not(.#{$prefix}--modal--enable-presence) {
    @include modal-animations(
      $has-presence: enabled('enable-presence') or $enable-presence
    );
  }
}

li {
  float: #{$global-left};

  font-size: $breadcrumbs-item-font-size;
  color: $breadcrumbs-item-color-current;
  cursor: default;

  @if $breadcrumbs-item-uppercase {
    text-transform: uppercase;
  }

  @if $breadcrumbs-item-separator {
    // Need to escape the backslash
    $separator: if($global-text-direction == 'ltr', $breadcrumbs-item-separator-item, $breadcrumbs-item-separator-item-rtl);

    &:not(:last-child) {
      &::after {
        position: relative;
        margin: 0 $breadcrumbs-item-margin;
        opacity: 1;
        content: $separator;
        color: $breadcrumbs-item-separator-color;
      }
    }
  }
  @else {
    margin-#{$global-right}: $breadcrumbs-item-margin;
  }
}

#{$child-selector} {
  margin: 0;
  margin-#{$global-right}: $spacing;
  margin-bottom: $spacing;
  font-size: map-get($button-sizes, default);

  @if $global-flexbox {
    flex: 0 0 auto;
  }

  &:last-child {
    margin-#{$global-right}: 0;
  }

  @if not $buttongroup-radius-on-each {
    border-radius: 0;

    &:first-child {
      border-top-#{$global-left}-radius: $button-radius;
      border-bottom-#{$global-left}-radius: $button-radius;
    }

    &:last-child {
      border-top-#{$global-right}-radius: $button-radius;
      border-bottom-#{$global-right}-radius: $button-radius;
    }
  }
}

@mixin button-group-unstack(
  $selector: $buttongroup-child-selector
) {
  #{$selector} {
